    if (M === 0) return 0;
    const N = grid[0].length;
    if (N === 0) return 0;

    // S[i][j] stores the Set of all possible XOR sums to reach (i, j)
    // Initialize S as M x N array of Sets
    const S = Array(M).fill(0).map(() => Array(N).fill(0).map(() => new Set()));

    // Base case (0, 0)
    S[0][0].add(grid[0][0]);

    // Fill the first row (only move right)
    for (let j = 1; j < N; j++) {
        const currentVal = grid[0][j];
        // We only come from (0, j-1)
