        const currentVal = grid[i][0];
        // We only come from (i-1, 0)
        for (const prevXOR of S[i - 1][0]) {
            S[i][0].add(prevXOR ^ currentVal);
        }
    }

    // Fill the rest of the grid
    for (let i = 1; i < M; i++) {
        for (let j = 1; j < N; j++) {
            const currentVal = grid[i][j];

            // From above (i-1, j)
            for (const prevXOR of S[i - 1][j]) {
                S[i][j].add(prevXOR ^ currentVal);
            }

            // From left (i, j-1)
            for (const prevXOR of S[i][j - 1]) {
                S[i][j].add(prevXOR ^ currentVal);
            }
        }
    }

    // The result is the minimum value in S[M-1][N-1]
    const finalSet = S[M - 1][N - 1];

    if (finalSet.size === 0) {
        // Should not happen given constraints M>=1, N>=1
        return 0; 
    }

    let minXOR = 1024; // Since max possible XOR is 1023
    for (const xorVal of finalSet) {
        if (xorVal < minXOR) {
            minXOR = xorVal;
        }
    }

    return minXOR;
}
